#include<bits/stdc++.h>
using namespace std;
int a[1000010],b[1000010],c[1000010],f[1000010],ans[1000010][2],x;
int main(void){
	std::ios::sync_with_stdio(0);
	int n,m,k;
	cin>>n>>m>>k;
	for(int i=0;i<1000001;i++)f[i]=i;
	for(int i=1;i<=n;i++)cin>>a[i];
	for(int i=1;i<=m;i++)cin>>b[i];
	for(int i=1;i<=k;i++)cin>>c[i];
	if(m>0)f[b[m]]=b[m]+1;
	for(int i=m-1;i>=1;i--)f[b[i]]=f[b[i]+1];
	for(int i=1;i<=n;i++){int kk;kk=f[a[i]],ans[kk][0]++;}
	for(int i=1;i<=10000;i++){
		for(int j=1;j<=k;j++){
			ans[f[i+c[j]]][1]+=ans[i][0];
		}
	}
	int i;i=10000;
	while(i--)if(ans[i][0]||ans[i][1])break;
	cout<<i<<'\n';
	for(int j=1;j<=i;j++)cout<<ans[j][0]<<' '<<ans[j][1]<<'\n';
	return false;
}
